 25→pub fn sanitize_transcript_for_semantic_review(
 26→    messages: &[TranscriptMessage],
 27→    max_chars: usize,
 28→) -> Vec<TranscriptMessage> {
 29→    let sanitized: Vec<TranscriptMessage> = messages
 30→        .iter()
 31→        .filter_map(|message| match message.role.as_str() {
 32→            "user" | "assistant" if message.tool_name.is_none() => {
 33→                let content = message.content.trim();
 34→                if content.is_empty() {
 35→                    None
 36→                } else {
 37→                    Some(TranscriptMessage {
 38→                        role: message.role.clone(),
 39→                        content: content.to_string(),
 40→                        tool_name: None,
 41→                        tool_input: None,
 42→                        timestamp: message.timestamp.clone(),
 43→                    })
 44→                }
 45→            }
 46→            "assistant" => message.tool_name.as_ref().map(|tool_name| TranscriptMessage {
 47→                role: "assistant".to_string(),
 48→                content: format!("used tool {}.", tool_name),
 49→                tool_name: None,
 50→                tool_input: None,
 51→                timestamp: message.timestamp.clone(),
 52→            }),
 53→            _ => None,
 54→        })
 55→        .collect();
 56→
 57→    if max_chars == 0 {
 58→        return Vec::new();
 59→    }
 60→
 61→    let mut kept = Vec::new();
 62→    let mut used = 0usize;
 63→
 64→    for message in sanitized.into_iter().rev() {
 65→        let len = message.content.chars().count();
 66→        if kept.is_empty() && len > max_chars {
 67→            kept.push(TranscriptMessage {
 68→                content: truncate_for_budget(&message.content, max_chars),
 69→                ..message
 70→            });
 71→            break;
 72→        }
 73→
 74→        if used + len > max_chars {
 75→            continue;
 76→        }
 77→
 78→        used += len;
 79→        kept.push(message);
 80→    }
 81→
 82→    kept.reverse();
 83→    kept
 84→}
