 68→pub fn list_worktrees(repo: &Repository) -> Result<Vec<WorktreeInfo>, String> {
 69→    let mut worktrees = Vec::new();
 70→    let wt_names = repo
 71→        .worktrees()
 72→        .map_err(|e| format!("Failed to list worktrees: {}", e))?;
 73→
 74→    for name in wt_names.iter() {
 75→        if let Some(name) = name {
 76→            if let Ok(wt) = repo.find_worktree(name) {
 77→                let wt_path = wt.path().to_string_lossy().to_string();
 78→                // Try to detect branch from worktree
 79→                let branch = detect_worktree_branch(&wt_path).unwrap_or_else(|| name.to_string());
 80→                worktrees.push(WorktreeInfo {
 81→                    path: wt_path,
 82→                    branch,
 83→                    is_main: false,
 84→                });
 85→            }
 86→        }
 87→    }
 88→
 89→    Ok(worktrees)
 90→}
