251→#[tauri::command]
252→fn get_entire_logs(repo_path: String, tail_lines: u32) -> Result<EntireLogResult, String> {
253→    let log_path = std::path::Path::new(&repo_path).join(".entire/logs/entire.log");
254→    if !log_path.exists() {
255→        return Err("No log file found".to_string());
256→    }
257→
258→    let metadata = std::fs::metadata(&log_path)
259→        .map_err(|e| format!("Failed to read log metadata: {}", e))?;
260→    let file_size_bytes = metadata.len();
261→
262→    let file = std::fs::File::open(&log_path)
263→        .map_err(|e| format!("Failed to open log file: {}", e))?;
264→
265→    // Count total lines
266→    let reader = BufReader::new(&file);
267→    let all_lines: Vec<String> = reader.lines().filter_map(|l| l.ok()).collect();
268→    let total_lines = all_lines.len() as u32;
269→
270→    // Take last N lines
271→    let start = all_lines.len().saturating_sub(tail_lines as usize);
272→    let lines = all_lines[start..].to_vec();
273→
274→    Ok(EntireLogResult {
275→        lines,
276→        total_lines,
277→        file_size_bytes,
278→    })
279→}
