757→#[cfg_attr(mobile, tauri::mobile_entry_point)]
758→pub fn run() {
759→    tauri::Builder::default()
760→        .plugin(tauri_plugin_opener::init())
761→        .plugin(tauri_plugin_dialog::init())
762→        .plugin(tauri_plugin_window_state::Builder::default().build())
763→        .manage(Mutex::new(AppState {
764→            watched_repos: HashSet::new(),
765→        }))
766→        .manage(Mutex::new(ghostty::GhosttyState::new()))
767→        .setup(|app| {
768→            // Start the ghostty tick loop on the MAIN THREAD via a Cocoa timer.
769→            // ghostty_app_tick processes Cocoa/Metal events and must run on the
770→            // main thread.
771→            {
772→                use block2::RcBlock;
773→                use objc2_foundation::NSTimer;
774→
775→                let handle = app.handle().clone();
776→                let tick_block = RcBlock::new(move |_timer| {
777→                    let state = handle.state::<Mutex<ghostty::GhosttyState>>();
778→                    let mutex = state.inner();
779→                    if let Ok(gs) = mutex.lock() {
780→                        if let Some(app) = gs.app.as_ref() {
781→                            app.tick();
782→                        }
783→                    }
784→                });
785→
786→                let _tick_timer = unsafe {
787→                    NSTimer::scheduledTimerWithTimeInterval_repeats_block(
788→                        1.0 / 60.0,
789→                        true,
790→                        &tick_block,
791→                    )
792→                };
793→            }
794→
795→            // System tray
796→            use tauri::menu::{MenuBuilder, MenuItemBuilder};
797→            use tauri::tray::TrayIconBuilder;
798→            use tauri::Manager;
799→
800→            let show = MenuItemBuilder::with_id("show", "Show Entire").build(app)?;
801→            let quit = MenuItemBuilder::with_id("quit", "Quit").build(app)?;
802→            let menu = MenuBuilder::new(app)
803→                .item(&show)
804→                .separator()
805→                .item(&quit)
806→                .build()?;
807→
808→            let _tray = TrayIconBuilder::new()
809→                .tooltip("Entire Desktop")
810→                .menu(&menu)
811→                .on_menu_event(move |app, event| {
812→                    match event.id().as_ref() {
813→                        "show" => {
814→                            if let Some(window) = app.get_webview_window("main") {
815→                                let _ = window.show();
816→                                let _ = window.set_focus();
817→                            }
818→                        }
819→                        "quit" => {
820→                            app.exit(0);
821→                        }
822→                        _ => {}
823→                    }
824→                })
825→                .on_tray_icon_event(|tray, event| {
826→                    if let tauri::tray::TrayIconEvent::Click { .. } = event {
827→                        let app = tray.app_handle();
828→                        if let Some(window) = app.get_webview_window("main") {
829→                            let _ = window.show();
830→                            let _ = window.set_focus();
831→                        }
832→                    }
833→                })
834→                .build(app)?;
835→
836→            Ok(())
837→        })
838→        .invoke_handler(tauri::generate_handler![
839→            debug_log,
840→            list_repos,
841→            register_repo,
842→            unregister_repo,
843→            block_repo,
844→            get_app_settings,
845→            save_app_settings,
846→            create_worktree,
847→            delete_worktree,
848→            delete_branch,
849→            list_checkpoints,
850→            get_transcript,
851→            get_checkpoint_diff,
852→            run_checkpoint_semantic_review,
853→            get_branch_diff,
854→            list_sessions,
855→            get_entire_settings,
856→            get_entire_logs,
857→            get_checkpoint_logs,
858→            get_raw_checkpoint_metadata,
859→            get_raw_session_file,
860→            launch_ghostty_agent,
861→            list_trails,
862→            watch_repo,
863→            ghostty::commands::ghostty_create_surface,
864→            ghostty::commands::ghostty_destroy_surface,
865→            ghostty::commands::ghostty_update_overlay,
866→            ghostty::commands::ghostty_show_overlay,
867→            ghostty::commands::ghostty_focus_overlay,
868→            ghostty::commands::ghostty_send_text,
869→        ])
870→        .run(tauri::generate_context!())
871→        .expect("error while running tauri application");
872→}
