373→  function handleBranchDeleted(branchName: string, repoPath: string) {
374→    const tabsToRemove = tabs.filter(
375→      (tab) =>
376→        tab.kind === "branch" &&
377→        tab.worktree === null &&
378→        tab.branch === branchName &&
379→        tab.repoPath === repoPath
380→    );
381→
382→    if (tabsToRemove.length === 0) {
383→      return;
384→    }
385→
386→    const nextTabs = tabs.filter((tab) => !tabsToRemove.some((candidate) => candidate.id === tab.id));
387→    setTabs(nextTabs);
388→
389→    if (tabsToRemove.some((tab) => tab.id === activeTabId) && nextTabs.length > 0) {
390→      setActiveTabId(nextTabs[0].id);
391→    }
392→
393→    setWorkspaceMap((prev) => {
394→      const next = new Map(prev);
395→      for (const tab of tabsToRemove) {
396→        const closedWorkspace = next.get(tab.id);
397→        for (const surfaceId of collectWorkspaceSurfaceIds(closedWorkspace)) {
398→          invoke("ghostty_destroy_surface", { surfaceId }).catch(console.error);
399→        }
400→        next.delete(tab.id);
401→      }
402→      return next;
403→    });
404→  }
