 89→/// List all checkpoints from the entire/checkpoints/v1 branch
 90→pub fn list_checkpoints(
 91→    repo: &Repository,
 92→    filter_branch: &str,
 93→) -> Result<Vec<CheckpointSummary>, String> {
 94→    let branch_ref = match repo.find_branch("entire/checkpoints/v1", git2::BranchType::Local) {
 95→        Ok(b) => b,
 96→        Err(_) => return Ok(Vec::new()), // No checkpoints branch yet
 97→    };
 98→
 99→    let commit = branch_ref
100→        .get()
101→        .peel_to_commit()
102→        .map_err(|e| format!("Failed to get checkpoint commit: {}", e))?;
103→
104→    let tree = commit
105→        .tree()
106→        .map_err(|e| format!("Failed to get tree: {}", e))?;
107→
108→    let mut checkpoints = Vec::new();
109→
110→    // Walk the sharded directory structure: <id[:2]>/<id[2:]>/metadata.json
111→    tree.walk(git2::TreeWalkMode::PreOrder, |dir, entry| {
112→        let name = match entry.name() {
113→            Some(n) => n,
114→            None => return git2::TreeWalkResult::Ok,
115→        };
116→
117→        // Look for metadata.json at the checkpoint level (e.g., "a1/b2c3d4/metadata.json")
118→        if name == "metadata.json" && !dir.is_empty() {
119→            // dir looks like "a1/b2c3d4/" — that's 2 levels deep
120→            let parts: Vec<&str> = dir.trim_end_matches('/').split('/').collect();
121→            if parts.len() == 2 {
122→                // This is a root checkpoint metadata.json
123→                if let Ok(blob) = repo.find_blob(entry.id()) {
124→                    if let Ok(content) = std::str::from_utf8(blob.content()) {
125→                        if let Ok(meta) = serde_json::from_str::<RawCheckpointMetadata>(content) {
126→                            let branch = meta.branch.clone().unwrap_or_default();
127→                            if filter_branch.is_empty() || branch == filter_branch {
128→                                let cp = build_checkpoint_summary(
129→                                    repo,
130→                                    &tree,
131→                                    dir,
132→                                    &meta,
133→                                );
134→                                if let Ok(cp) = cp {
135→                                    checkpoints.push(cp);
136→                                }
137→                            }
138→                        }
139→                    }
140→                }
141→            }
142→        }
143→
144→        git2::TreeWalkResult::Ok
145→    })
146→    .map_err(|e| format!("Tree walk error: {}", e))?;
147→
148→    // Sort by created_at descending
149→    checkpoints.sort_by(|a, b| b.created_at.cmp(&a.created_at));
150→
151→    Ok(checkpoints)
152→}
153→
154→fn build_checkpoint_summary(
155→    repo: &Repository,
156→    _tree: &git2::Tree,
157→    dir: &str,
158→    meta: &RawCheckpointMetadata,
159→) -> Result<CheckpointSummary, String> {
160→    let checkpoint_id = meta
161→        .checkpoint_id
162→        .clone()
163→        .unwrap_or_else(|| dir.replace('/', ""));
164→
165→    let mut sessions = Vec::new();
166→    let mut earliest_created_at: Option<String> = None;
167→    // Read session metadata from subdirectories (0/, 1/, etc.)
168→    if let Some(refs) = &meta.sessions {
169→        for (i, session_ref) in refs.iter().enumerate() {
170→            let session_dir = format!("{}{}/", dir, i);
171→            let session_meta_path = format!("{}metadata.json", session_dir);
172→
173→            // Try to read session metadata from the tree
174→            if let Ok(session_meta) = read_blob_from_tree(repo, &session_meta_path) {
175→                if let Ok(sm) = serde_json::from_str::<RawSessionMetadata>(&session_meta) {
176→                    // Track earliest created_at across sessions
177→                    if let Some(ref ca) = sm.created_at {
178→                        if earliest_created_at.as_ref().map_or(true, |e| ca < e) {
179→                            earliest_created_at = Some(ca.clone());
180→                        }
181→                    }
182→
183→                    // Count steps from transcript if available
184→                    let step_count = count_transcript_steps(repo, session_ref, &session_dir);
185→
186→                    sessions.push(SessionSummary {
187→                        session_id: sm.session_id.unwrap_or_default(),
188→                        agent: sm.agent.unwrap_or_else(|| "Unknown".to_string()),
189→                        model: sm.model,
190→                        step_count,
191→                        summary: sm.summary,
192→                        token_usage: sm.token_usage,
193→                        initial_attribution: sm.initial_attribution,
194→                    });
195→                }
196→            }
197→        }
198→    }
199→
200→    // Use checkpoint metadata fields first, fall back to session-derived values
201→    let created_at = meta
202→        .created_at
203→        .clone()
204→        .or(earliest_created_at)
205→        .unwrap_or_default();
206→
207→    let branch_name = meta.branch.clone().unwrap_or_default();
208→
209→    // Resolve commit_sha and commit_message from the branch's git history
210→    // The checkpoint corresponds to the most recent commit on the branch at created_at time
211→    let (commit_sha, commit_message) = meta
212→        .commit_sha
213→        .clone()
214→        .filter(|s| !s.is_empty())
215→        .map(|sha| {
216→            let msg = meta.commit_message.clone().unwrap_or_default();
217→            (sha, msg)
218→        })
219→        .unwrap_or_else(|| {
220→            resolve_commit_from_branch(repo, &branch_name, &created_at)
221→                .unwrap_or_default()
222→        });
223→
224→    Ok(CheckpointSummary {
225→        checkpoint_id,
226→        branch: branch_name,
227→        commit_sha,
228→        commit_message,
229→        files_touched: meta.files_touched.clone().unwrap_or_default(),
230→        sessions,
231→        token_usage: meta.token_usage.clone(),
232→        created_at,
233→    })
234→}
