351→fn read_blob_from_tree(repo: &Repository, path: &str) -> Result<String, String> {
352→    let branch_ref = repo
353→        .find_branch("entire/checkpoints/v1", git2::BranchType::Local)
354→        .map_err(|e| format!("No checkpoint branch: {}", e))?;
355→
356→    let commit = branch_ref
357→        .get()
358→        .peel_to_commit()
359→        .map_err(|e| format!("Failed to peel: {}", e))?;
360→
361→    let tree = commit
362→        .tree()
363→        .map_err(|e| format!("Failed to get tree: {}", e))?;
364→
365→    let entry = tree
366→        .get_path(std::path::Path::new(path))
367→        .map_err(|e| format!("Path not found: {}", e))?;
368→
369→    let blob = repo
370→        .find_blob(entry.id())
371→        .map_err(|e| format!("Failed to read blob: {}", e))?;
372→
373→    std::str::from_utf8(blob.content())
374→        .map(|s| s.to_string())
375→        .map_err(|e| format!("Invalid UTF-8: {}", e))
376→}
377→

 40→    let mut branches = Vec::new();
 41→    let head = repo.head().ok();
 42→    let head_name = head
 43→        .as_ref()
 44→        .and_then(|h| h.shorthand().map(|s| s.to_string()));
 45→
 46→    let git_branches = repo
 47→        .branches(Some(git2::BranchType::Local))
 48→        .map_err(|e| format!("Failed to list branches: {}", e))?;
 49→
 50→    for branch_result in git_branches {
 51→        let (branch, _) = branch_result.map_err(|e| format!("Branch error: {}", e))?;
 52→        if let Some(name) = branch.name().ok().flatten() {
 53→            // Skip entire/ internal branches
 54→            if name.starts_with("entire/") {
 55→                continue;
 56→            }
 57→            branches.push(BranchInfo {
 58→                is_head: head_name.as_deref() == Some(name),
 59→                name: name.to_string(),
 60→                checkpoint_count: 0, // TODO: count from checkpoint branch
 61→            });
 62→        }
 63→    }
 64→
 65→    Ok(branches)
 66→}
